head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.hid_chkCvsslMgntNo = ""; //본선관리번호
scwin.hid_chkRegId = ""        //등록자 ID

scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strPreDate = scwin.strCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)

scwin.selpchClsCd = "1"; //매출입구분코드
scwin.MSG_FS_WRN_013 = "청구 데이타가 존재하지 않습니다.";				
scwin.MSG_FS_WRN_014 = "청구취소 데이타가 존재하지 않습니다.";				
scwin.MSG_FS_WRN_015 = "청구는 내부거래상태가 등록일때만 가능합니다.";						
scwin.MSG_FS_WRN_016 = "청구취소는 내부거래상태가 청구일때만 가능합니다.";	

/*
ASIS에서 주석 처리되어있는 이벤트
f_changeSellInfoWhole
f_save
f_validateSellInfo
f_certiLink

*/


//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    // 파라미터 받기
    scwin.param = $c.data.getParameter();
    scwin.flag = scwin.param.flag == null ? "" : scwin.param.flag;	
    scwin.bizDom = scwin.param.bizDom == null ? "" : scwin.param.bizDom;
    scwin.selPchLodeptCd = scwin.param.selPchLodeptCd == null ? "" : scwin.param.selPchLodeptCd;
    scwin.qryConDt = scwin.param.qryConDt == null ? "" : scwin.param.qryConDt;
    scwin.qryConLastDt = scwin.param.qryConLastDt == null ? "" : scwin.param.qryConLastDt;
    scwin.acctCd = scwin.param.acctCd == null ? "" : scwin.param.acctCd;
    scwin.acctNm = scwin.param.acctNm == null ? "" : scwin.param.acctNm;
    scwin.strbilgClntNo = scwin.param.bilgClntNo == null ? "" : scwin.param.bilgClntNo;
    scwin.strbilgClntNm = scwin.param.bilgClntNm == null ? "" : scwin.param.bilgClntNm;
    scwin.strlobranCd = scwin.param.strlobranCd == null ? "" : scwin.param.strlobranCd;
    scwin.strlobranNm = scwin.param.strlobranNm == null ? "" : scwin.param.strlobranNm;




    //공통코드데이터 호출   
    const codeOptions = [
        { grpCd: "SD187", compID: "acb_retStd" }, // 셀렉트
        { grpCd: "SD144", compID: "acb_mcomAssgnClsCd" }, // 셀렉트
        { grpCd: "SD113", compID: "acb_odrKndCd" }, // 셀렉트
        { grpCd: "LO111", compID: "acb_sellClntClsCd" }, // 셀렉트
        { grpCd: "FS500", compID: "acb_dcsnClsCd" } // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);	

    const param = [
        {
            compID : "acb_selfClsCd",
            method : "getCodeList",
            param1 : "SD114",
            param2 : 1,
            // param3: DsConstants.ODR_ALL,
            param3: DsConstants.ODR_CNTR,
            outputFields: ["CD", "CD_NM"]
        },
        {
            compID : "acb_selfClsCd",
            method : "getCodeList",
            param1 : "SD114",
            param2 : 1,
            param3: DsConstants.ODR_ALL,
            // param3: DsConstants.ODR_CNTR,
            outputFields: ["CD", "CD_NM"]
        }    
    ];
    $c.data.setDsCommonUtil(param);

    acb_bilgTrgtYn.setValue("1");
    scwin.btn_retrieve_onClickFmalPattern();

    //계정별 확정/미확정 조회 링크시
    if(scwin.flag != ""){
        dma_selldecunsetaggr_con.setArray(scwin.param.ds_selldecunsetaggr_con);						
        scwin.f_WholeRetrieve();

    }

    // 점소별 년매출 현황 링크시
    if(scwin.bizDom != ""){
        dma_selldecunsetaggr_con.setArray(scwin.param.ds_selldecunsetaggr_con);						
        scwin.f_WholeRetrieve();	
        scwin.f_BizDomRetrieve();

    }		

    if(scwin.selPchLodeptCd != ""){
        scwin.f_executeFromLinked();
    }
    gr_selldecunsetdetail.setColumnVisible("sellUpr0010", false);
    gr_selldecunsetdetail.setColumnVisible("sellUprEtc", false);
    gr_selldecunsetdetail.setColumnVisible("sellAmt0010", false);
    gr_selldecunsetdetail.setColumnVisible("sellAmtEtc", false);
    gr_selldecunsetdetail.setColumnVisible("sellVat0010", false);
    gr_selldecunsetdetail.setColumnVisible("sellVatEtc", false);
    gr_selldecunsetdetail.setColumnVisible("totAmt0010", false);
    gr_selldecunsetdetail.setColumnVisible("totAmtEtc", false);

    gr_selldecunsetdetail.setColumnVisible("sellUpr", true);
    gr_selldecunsetdetail.setColumnVisible("sellAmt", true);
    gr_selldecunsetdetail.setColumnVisible("vatAmt", true);
    gr_selldecunsetdetail.setColumnVisible("totAmt", true);

    rd_transCargoClsCd.setValue("");
    $c.gus.cfDisableObjects([ed_mrn, ed_msn, ed_hsn, acb_acctCd, acb_bilgTrgtYn, acb_prebilgCreatYn, acb_mcomAssgnClsCd, ed_vsslCd, ed_portcnt, acb_sellClntClsCd, acb_magamStd]);	
    div_qryConKnd5.setStyle("display", "none");
    scwin.udcOnCompleted();



};


//-------------------------------------------------------------------------
// 점소별 년매출 현황 링크시 
//-------------------------------------------------------------------------
scwin.f_BizDomRetrieve = function() {

    ed_bilgLodeptCd.setValue(dma_selldecunsetaggr_con.get("bilgLodeptCd"));
    // f_openCommonPopUp(1, ed_bilgLodeptCd.Text, txt_bilgLodeptNm.value, 'T', 'T');
    acb_qryConKnd.setValue("실적");
    ed_bilgClntNo.setValue(dma_selldecunsetaggr_con.get("bilgClntNo"));
    ica_qryConDtFm.setValue(dma_selldecunsetaggr_con.get("qryConDtFm"));
    ica_qryConDtTo.setValue(dma_selldecunsetaggr_con.get("qryConDtTo"));		
    rd_transCargoClsCd.setValue( dma_selldecunsetaggr_con.get("transCargoClsCd"));		
    acb_bizDomCd.setValue( dma_selldecunsetaggr_con.get("bizDomCd"));	
    ed_lineCd.setValue(	  dma_selldecunsetaggr_con.get("lineCd"));	
    scwin.btn_retrieve_onClick();


}


scwin.f_executeFromLinked = function() {

    ed_bilgLodeptCd.setValue(scwin.selPchLodeptCd);
    ica_qryConDtFm.setValue((scwin.qryConDt+01));
    ica_qryConDtTo.setValue(scwin.qryConLastDt);
    acb_qryConKnd.setValue("회계");
    if(scwin.acctCd != ""){
        acb_acctCd.setValue(scwin.acctCd);
    }
    scwin.btn_retrieve_onClick();

}


//-------------------------------------------------------------------------
// 조회 / f_Retrieve
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {
    //validation check     
    if(acb_qryConKnd.getValue() == "오더번호" || acb_qryConKnd.getValue() == "B/L" ){
        if(! await $c.gus.cfValidate([ed_bilgLodeptCd,ed_qryConCd])){
            return;
        }		
    } else {
        if(! await $c.gus.cfValidate([ed_bilgLodeptCd,ica_qryConDtFm,ica_qryConDtTo])){
            return;
        }		
    }

    let qryConKnd = ""

    dma_selldecunsetaggr_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
    dma_selldecunsetaggr_con.set("bizDomCd", acb_bizDomCd.getValue());
    if (cbx_impExpDomesticClsCd01.getValue() == "1"){
        dma_selldecunsetaggr_con.set("impExpDomesticClsCd01", "I");
    } 
    if (cbx_impExpDomesticClsCd02.getValue() == "1"){
        dma_selldecunsetaggr_con.set("impExpDomesticClsCd02", "O");
    }     	 	
    if (cbx_impExpDomesticClsCd03.getValue() == "1"){
        dma_selldecunsetaggr_con.set("impExpDomesticClsCd03", "D");
    }     	 	     	
    dma_selldecunsetaggr_con.set("bilgClntNo", ed_bilgClntNo.getValue());
    if(acb_qryConKnd.getValue() == "오더"){
        qryConKnd = "오더일자";
    } else if(acb_qryConKnd.getValue() == "실적"){
        qryConKnd = "실적일자";     	
    } else if(acb_qryConKnd.getValue() == "회계"){
        qryConKnd = "회계일자";     	
    } else if(acb_qryConKnd.getValue() == "오더번호"){
        qryConKnd = "오더번호";     	
    } else if(acb_qryConKnd.getValue() == "청구인식일"){
        qryConKnd = "청구인식일";     	
    } else if(acb_qryConKnd.getValue() == "B/L"){
        qryConKnd = "B/L";     	
    } else if(acb_qryConKnd.getValue() == "출발예정"){
        qryConKnd = "출발예정";     	
    }
    dma_selldecunsetaggr_con.set("qryConKnd", qryConKnd);
    dma_selldecunsetaggr_con.set("qryConDtFm", ica_qryConDtFm.getValue());
    dma_selldecunsetaggr_con.set("qryConDtTo", ica_qryConDtTo.getValue());
    // dma_selldecunsetaggr_con.set("qryConCd", ed_qryConCd.getValue());
    if(acb_qryConKnd2.getValue() == "CNTR"){
        qryConKnd2 = "CNTR-NO";
        cntrNo = ed_qryConCd3.getValue();
        commCd = '';     		
        commNm = '';     		
        blNo   = '';     		     		     			     		
    } else if(acb_qryConKnd2.getValue() == "품명"){
        qryConKnd2 = "품명코드";     
        commCd = ed_qryConCd2.getValue();
        cntrNo = '';     		     			
        commNm = '';     		
        blNo   = '';     		     		
    } else if(acb_qryConKnd2.getValue() == "품목"){
        qryConKnd2 = "품목명";     	
        commNm = ed_qryConCd2.getValue();     		
        cntrNo = '';     		   
        commCd = '';     		  			
        blNo   = '';     		     		     		     		
    } else if(acb_qryConKnd2.getValue() == "BL"){
        qryConKnd2 = "BL-NO";     	
        blNo   = ed_qryConCd3.getValue();     		
        cntrNo = '';
        commCd = '';     		
        commNm = '';     		     		
    }	

    dma_selldecunsetaggr_con.set("qryConKnd2", qryConKnd2);
    dma_selldecunsetaggr_con.set("qryConCd2", ed_qryConCd2.getValue());     	
    dma_selldecunsetaggr_con.set("cntrNo", cntrNo);     	
    dma_selldecunsetaggr_con.set("commCd", commCd);     	
    dma_selldecunsetaggr_con.set("commNm", commNm);     	
    dma_selldecunsetaggr_con.set("blNo", blNo);     	     	     	     	     	
    dma_selldecunsetaggr_con.set("wrkPlCd", ed_wrkPlCd.getValue());
    dma_selldecunsetaggr_con.set("dcsnClsCd", acb_dcsnClsCd.getValue()); 
    dma_selldecunsetaggr_con.set("lineCd", ed_lineCd.getValue());
    dma_selldecunsetaggr_con.set("vsslCd", ed_vsslCd.getValue());
    dma_selldecunsetaggr_con.set("portcnt", ed_portcnt.getValue());     	

    dma_selldecunsetaggr_con.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    dma_selldecunsetaggr_con.set("regId", ed_regId.getValue());
    dma_selldecunsetaggr_con.set("modId", ed_modId.getValue()); 

    dma_selldecunsetaggr_con.set("transCargoClsCd", rd_transCargoClsCd.getValue()); 	     	
    dma_selldecunsetaggr_con.set("acctCd", acb_acctCd.getValue());    	     	
    dma_selldecunsetaggr_con.set("sellItemCd", ed_sellItemCd.getValue());  	     	
    dma_selldecunsetaggr_con.set("odrKndCd", acb_odrKndCd.getValue());    	     	     	     	
    dma_selldecunsetaggr_con.set("sellClntClsCd", acb_sellClntClsCd.getValue());
    dma_selldecunsetaggr_con.set("mrn", ed_mrn.getValue());
    dma_selldecunsetaggr_con.set("msn", ed_msn.getValue());
    dma_selldecunsetaggr_con.set("hsn", ed_hsn.getValue());
    dma_selldecunsetaggr_con.set("bilgTrgtYn", acb_bilgTrgtYn.getValue());
    dma_selldecunsetaggr_con.set("prebilgCreatYn", acb_prebilgCreatYn.getValue());     	     	
    dma_selldecunsetaggr_con.set("gubun", acb_gubun.getValue());
    dma_selldecunsetaggr_con.set("mcomAssgnClsCd", acb_mcomAssgnClsCd.getValue());
    dma_selldecunsetaggr_con.set("magamStd", acb_magamStd.getValue());     	
    dma_selldecunsetaggr_con.set("selfClsCd", acb_selfClsCd.getValue());     	     	

    dma_selldecunsetaggr_con.set("closeYm", acb_retStd.getValue());

    if (acb_retStd.getValue() == '0') {
        dma_selldecunsetaggr_con.set("retStd", '0');
    } else {
        dma_selldecunsetaggr_con.set("retStd", '1');
    }

    dma_selldecunsetaggr_con.set("aggbilgClntNo", ed_bilgClntNo.getValue());
    dma_selldecunsetaggr_con.set("aggsellItemCd", '');     	
    dma_selldecunsetaggr_con.set("aggtaxnClsCd", '');     	     	

    if (cbx_crnYn.getValue() == "1"){
        dma_selldecunsetaggr_con.set("crnYn", "Y");
    } else {
        dma_selldecunsetaggr_con.set("crnYn", "N");     	
    }

    if (cbx_upClsCd.getValue() == "1"){
        dma_selldecunsetaggr_con.set("upDownClsCd", "UP");
    } else if(cbx_downClsCd.checked){
        dma_selldecunsetaggr_con.set("upDownClsCd", "DOWN");
    } else {
        dma_selldecunsetaggr_con.set("upDownClsCd", "NULL");
    }


    if (cbx_newQryYn.getValue() == "1"){
        dma_selldecunsetaggr_con.set("newQryYn", "NEW");
    }



    //상세화면 데이타 Clear
    ds_selldecunsetdetail.removeAll();
    spa_totalRows2.setValue(0);

    $c.sbm.execute(sbm_selldecunsetaggr_retrieve);


    if (cbx_detailAllYn.getValue() == "1"){    	
        scwin.f_SellingDecDetailRetrieve();   		
    }	

};


//-------------------------------------------------------------------------
// 조회 완료시
//-------------------------------------------------------------------------
scwin.sellAggr_submitDone = function (e) {

    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)return; //onFail

        spa_totalRows.setValue(ds_selldecunsetaggr.getTotalRow());

        if(ds_selldecunsetaggr.getTotalRow() == 0) {
            $c.win.alert(MSG_CM_WRN_002);
            // ed_bilgLodeptCd.focus();
        }
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }

};



//-------------------------------------------------------------------------
// 상단 그리드 데이터 로드 완료 시 
//-------------------------------------------------------------------------
scwin.ds_selldecunsetaggr_ondataload = function () {
    gr_selldecunsetaggr.setFocusedCell(0, 0);

};


//-------------------------------------------------------------------------
// 상단 그리드 셀 클릭시
//-------------------------------------------------------------------------
scwin.gr_sellAggr_onclick = function (rowIndex, columnIndex, columnId) {

    if(rowIndex >= 0 ) {
        if(cbx_detailAllYn.getValue() == "0"){
            scwin.f_SellingDecDetailRetrieve(rowIndex);
        }
    }
};

//-------------------------------------------------------------------------
// 내부매출 상세데이터 가져오기
//-------------------------------------------------------------------------
scwin.f_SellingDecDetailRetrieve = function(row) {
    scwin.f_CreateDataSet(row);

if(cbx_detailAllYn.getValue() == "1") {
        //2009.12.04 수정
        //검색조건에 청구처를 입력하지 않았으면 NULL
        //청구처를 입력했으면 N
        //청구처를 입력하고 사업자기준을 체크했다면 Y
        if (dma_selldecunsetdetail_con.getValue("aggbilgClntNo") != null && dma_selldecunsetdetail_con.get("aggbilgClntNo") != "") {
            if(cbx_crnYn.getValue() == "1") {
                dma_selldecunsetdetail_con.set("crnYn", "Y");
            } else {
                dma_selldecunsetdetail_con.set("crnYn", "N");
                }
        } else {
            dma_selldecunsetdetail_con.set("crnYn", "");
        }
    } 
    else {
        dma_selldecunsetdetail_con.set("aggbilgClntNo", ds_selldecunsetaggr.getCellData(row,"bilgClntNo"));
        dma_selldecunsetdetail_con.set("aggsellItemCd", ds_selldecunsetaggr.getCellData(row,"sellItemCd"));
        dma_selldecunsetdetail_con.set("aggtaxnClsCd", ds_selldecunsetaggr.getCellData(row,"taxnClsCd"));
        dma_selldecunsetdetail_con.set("schGb", ds_selldecunsetaggr.getCellData(row,"schGb"));
    }

    if (cbx_sumDc.getValue() == "1"){
        dma_selldecunsetdetail_con.set("sumQryYn", "Y");
    } else {
        dma_selldecunsetdetail_con.set("sumQryYn", "N");     	
    }

    $c.sbm.execute(sbm_selldecunsetdetail_retrieve)
}



//-------------------------------------------------------------------------
// 내부매출 조회조건 DataSet 만들기
//-------------------------------------------------------------------------
scwin.f_CreateDataSet = function(row) {
    let dataCopy = dma_selldecunsetaggr_con.getArray();
    dma_selldecunsetdetail_con.setArray(dataCopy);


    if(cbx_detailAllYn.getValue() == "1") {
        //2009.12.04 수정
        //검색조건에 청구처를 입력하지 않았으면 NULL
        //청구처를 입력했으면 N
        //청구처를 입력하고 사업자기준을 체크했다면 Y
        if (dma_selldecunsetdetail_con.getValue("aggbilgClntNo") != null && dma_selldecunsetdetail_con.get("aggbilgClntNo") != "") {
            if(cbx_crnYn.getValue() == "1") {
                dma_selldecunsetdetail_con.set("crnYn", "Y");
            } else {
                dma_selldecunsetdetail_con.set("crnYn", "N");
                }
        } else {
            dma_selldecunsetdetail_con.set("crnYn", "");
        }
    } 
    else {
        dma_selldecunsetdetail_con.set("aggbilgClntNo", ds_selldecunsetaggr.getCellData(row,"bilgClntNo"));
        dma_selldecunsetdetail_con.set("aggsellItemCd", ds_selldecunsetaggr.getCellData(row,"sellItemCd"));
        dma_selldecunsetdetail_con.set("aggtaxnClsCd", ds_selldecunsetaggr.getCellData(row,"taxnClsCd"));
        dma_selldecunsetdetail_con.set("schGb", ds_selldecunsetaggr.getCellData(row,"schGb"));
    }

    if (cbx_sumDc.getValue() == "1"){
        dma_selldecunsetdetail_con.set("sumQryYn", "Y");
    } else {
        dma_selldecunsetdetail_con.set("sumQryYn", "N");     	
    }

    // $c.sbm.execute(sbm_selldecunsetdetail_retrieve)
}



//-------------------------------------------------------------------------
// 계정별 확정/미확정 호출시 조회
//-------------------------------------------------------------------------
scwin.f_WholeRetrieve = function() {
    ed_bilgLodeptCd.setValue(dma_selldecunsetaggr_con.get("bilgLodeptCd"));
    // f_openCommonPopUp(1, ed_bilgLodeptCd.Text, txt_bilgLodeptNm.value, 'T', 'T');
    if(dma_selldecunsetaggr_con.get("dcsnClsCd") == "DCSN"){		
        acb_qryConKnd.setValue("회계");
    } else if(dma_selldecunsetaggr_con.get("dcsnClsCd") == "NODCSN"){
        acb_qryConKnd.setValue("실적");
        acb_dcsnClsCd.setValue("3");
        cbx_downClsCdsetValue("1");			
    } else if(dma_selldecunsetaggr_con.get("dcsnClsCd") == "3"){
        acb_qryConKnd.setValue("실적");
        acb_dcsnClsCd.setValue("3");		
    } else if(dma_selldecunsetaggr_con.get("dcsnClsCd") == "2"){
        acb_qryConKnd.setValue("실적");
        acb_dcsnClsCd.setValue("2");		
        cbx_downClsCdsetValue("1");
    }		

    ica_qryConDtFm.setValue(dma_selldecunsetaggr_con.get("qryConDtFm"));
    ica_qryConDtTo.setValue(dma_selldecunsetaggr_con.get("qryConDtTo"));
    if(dma_selldecunsetaggr_con.get("accCd") == "GNRL"){		
        acb_acctCd.setValue("4101010");
    } else if(dma_selldecunsetaggr_con.get("accCd") == "fCL"){		
        acb_acctCd.setValue("4101020");		
    } else if(dma_selldecunsetaggr_con.get("accCd") == "EQ"){		
        acb_acctCd.setValue("4101040");		
    } else if(dma_selldecunsetaggr_con.get("accCd") == "CON"){		
        acb_acctCd.setValue("4101140");		
    }

    acb_retStd.setValue(dma_selldecunsetaggr_con.get("retStd"));

    scwin.btn_retrieve_onClick();
};


scwin.btn_retrieve_onClickFmalPattern = function() {


}


//-------------------------------------------------------------------------
// 조회조건 날짜세팅
//-------------------------------------------------------------------------
setTimeout (scwin.udcOnCompleted = function() {
