//-------------------------------------------------------------------------
// 오더별 매출 현황 데이터 로드시
//-------------------------------------------------------------------------
scwin.ds_selldecunsetdetail_ondataload = function () {
    spa_totalRows2.setValue(ds_selldecunsetdetail.getTotalRow());
	let size20 = 0;
    let size40 = 0;
    let size45 = 0;
    for(i=0; i < ds_selldecunsetdetail.getTotalRow(); i++) {
        let cntrSize = ds_selldecunsetdetail.getCellData(i, "cntrSizCd");
        if(cntrSize == "20") {
            ++size20;
        }else if (cntrSize == "40") {
            ++size40
        }else {
            ++size45;
        }
    }

    let sizeCntTxt = "20_SIZE " + size20 + "건, 40_SIZE " + size40 + "건";


    spa_sizeCntMsg.setValue(sizeCntTxt)

    gr_selldecunsetdetail.setFocusedCell(0, 0);

};


