//-------------------------------------------------------------------------
// 상세 그리드 더블클릭
//-------------------------------------------------------------------------
scwin.gr_detail_DblClick = async function (rowIndex, columnIndex, columnId) {
	if(rowIndex >= 0){
		if (ds_selldecunsetdetail.getCellData(rowIndex, "schGb") == "D") {
			if(columnId == "cntrNo" && ds_selldecunsetdetail.getCellData(rowIndex, "cntrNo") != ""){ 
				scwin.f_cntrNoDetail(ds_selldecunsetdetail.getCellData(rowIndex, "cntrNo"));
			}	
			if(columnId == "odrNo" && ds_selldecunsetdetail.getCellData(rowIndex, "odrNo") != ""){
				scwin.f_orderDetail(ds_selldecunsetdetail.getCellData(rowIndex, "odrNo"));
			}
			if(columnId == "sellItemNm" && ds_selldecunsetdetail.getCellData(rowIndex, "sellItemNm") != ""){
				scwin.f_sellItemDetail(ds_selldecunsetdetail.getCellData(rowIndex, "odrNo"));
			}		

			// f_RetrieveFmalPattern();
		} else {
			if(columnId == "odrNo" && ds_selldecunsetdetail.getCellData(rowIndex, "odrNo") != ""){
				await $c.gus.cfShowSlipInfo(ds_selldecunsetdetail.getCellData(rowIndex,"odrNo"));
			}
		}

	}


};


//-------------------------------------------------------------------------
// GRID에서 선택된 cntrNo 세부정보 확인 : 해당 cntrNo 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_cntrNoDetail = function(cntrNo) {
    let url = "/ui/ds/as/cstmrsrvc/coafmgnt/as_102_01_02b.xml"; 
    let menuNm = "컨테이너화물추적"

    let param = {
        cntrNo : cntrNo
    }

    let option = {
        id: "taxPop", 
        type: "",
        menuName: "컨테이너화물추적",
        width:  1100,                   
        height: 650
    };

    $c.win.openMenu(menuNm, url, "as_102_01_02b.xml", param, option)
}

//-------------------------------------------------------------------------
// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_orderDetail = function(arg) {
    let url = "";
    let menuNm = "";
    let pgmId = "";

    let param = {
    }
    if(arg.substring(1,2) == "B") {
        url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_02t.xml";
        menuNm = "벌크오더";
        pgmId = "sd_402_01_02t.xml";

    } else if(arg.substring(1,2) == "C") {
        param.odrNo = arg;
        param.odrKndCd = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "odrKndCd");
        param.type = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "cntrTypeCd");
        param.linkPage = "";
        param.cvsslMgntNo = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "cvsslMgntNo");
        param.blNo = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "blNo");
        param.lineCd = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "lineCd");
        param.mcomAssgnClsCd = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "mcomAssgnClsCd");
        param.bookingNo = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "bookingNo");
        param.pickupdt = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "pickupdt");
        param.pickuphh = ds_selldecunsetdetail.getCellData(gr_selldecunsetdetail.getFocusedRowIndex(), "pickuphh");
        url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml"
        menuNm = "컨테이너오더"
        pgmId = "sd_402_01_11t.xml";
    } else if(arg.substring(1,2) == "Z") {
        url = "/ui/ds/fs/bilg/fs_202_03_02b.xml"
        menuNm = "일반청구오더등록"
        pgmId = "fs_202_03_02b.xml";
    }


    if(arg.substring(1,2) == "Z") {
        param.odrNo = arg;
        param.flag = "DETAIL";    
    } else {
        param.odrNo = arg;
        param.type = "retrieve";
    }

    let option = {
        id: "taxPop", 
        type: "",
        menuName: menuNm,
        width:  1100,                   
        height: 650
    };

    $c.win.openMenu(menuNm, url, pgmId, param, option)
}


